import{_ as i,c as l,o as r,ah as t,ai as e}from"./chunks/framework.Cnj7lwEt.js";const b=JSON.parse('{"title":"91GIT - GitHub中国中継","description":"","frontmatter":{},"headers":[],"relativePath":"ja/91git.md","filePath":"ja/91git.md"}'),n={name:"ja/91git.md"};function s(o,a,h,d,c,_){return r(),l("div",null,a[0]||(a[0]=[t('<h1 id="_91git-github中国中継" tabindex="-1">91GIT - GitHub中国中継 <a class="header-anchor" href="#_91git-github中国中継" aria-label="Permalink to “91GIT - GitHub中国中継”">​</a></h1><p><strong>アクセスURL:</strong> <a href="https://91git.com/" target="_blank" rel="noreferrer">https://91git.com/</a></p><h2 id="_01-1-プロジェクト概要" tabindex="-1">01.1- プロジェクト概要 <a class="header-anchor" href="#_01-1-プロジェクト概要" aria-label="Permalink to “01.1- プロジェクト概要”">​</a></h2><p>GitHub中国中継 —— GitHubリポジトリをワンクリックで検索し、ソースコードとリリースアセットを自動パッケージ化して、ダウンロード用の圧縮ファイルを生成します。</p><p>国内のネットワーク環境に特化して設計され、開発者がGitHubプロジェクトリソースに迅速にアクセスできるよう支援します。</p><p><img src="'+e+'" alt="alt text"></p><h2 id="_01-2-機能特徴" tabindex="-1">01.2- 機能特徴 <a class="header-anchor" href="#_01-2-機能特徴" aria-label="Permalink to “01.2- 機能特徴”">​</a></h2><ul><li>🔍 <strong>キーワード検索</strong> - キーワードでGitHubリポジトリを検索し、Star数でソート</li><li>📥 <strong>ワンクリックパッケージング</strong> - ソースコード + リリースアセットを自動ダウンロードし、二重暗号化圧縮ファイルを生成</li><li>🔥 <strong>GitHub人気</strong> - 今週新規作成された高StarリポジトリTop 10を表示</li><li>📊 <strong>サイト人気パッケージ</strong> - 当日/当月のパッケージング回数が最も多いリポジトリを表示</li><li>⏱️ <strong>自動クリーンアップ</strong> - パッケージファイルはダウンロードされない場合3分後に自動削除、サーバースペースを節約</li></ul><h2 id="_01-3-技術スタック" tabindex="-1">01.3- 技術スタック <a class="header-anchor" href="#_01-3-技術スタック" aria-label="Permalink to “01.3- 技術スタック”">​</a></h2><ul><li><strong>フロントエンド</strong>: React + TypeScript + Vite + Tailwind CSS</li><li><strong>アニメーション</strong>: Framer Motion</li><li><strong>バックエンド</strong>: Node.js + Express</li><li><strong>パッケージング</strong>: archiver（ZIP）</li><li><strong>暗号化</strong>: AES-256 + ZIPパスワード</li></ul><h2 id="_01-4-ユースケース" tabindex="-1">01.4- ユースケース <a class="header-anchor" href="#_01-4-ユースケース" aria-label="Permalink to “01.4- ユースケース”">​</a></h2><h3 id="開発者向け" tabindex="-1">開発者向け <a class="header-anchor" href="#開発者向け" aria-label="Permalink to “開発者向け”">​</a></h3><ul><li>GitHubプロジェクトのソースコードを迅速に取得</li><li>完全なリリースアセットをダウンロード</li><li>プロジェクトリソースをパッケージ化して共有</li></ul><h3 id="研究者向け" tabindex="-1">研究者向け <a class="header-anchor" href="#研究者向け" aria-label="Permalink to “研究者向け”">​</a></h3><ul><li>研究ツールをバッチダウンロード</li><li>オープンソースプロジェクトをアーカイブ</li><li>ローカルリソースライブラリを構築</li></ul><h3 id="企業ユーザー向け" tabindex="-1">企業ユーザー向け <a class="header-anchor" href="#企業ユーザー向け" aria-label="Permalink to “企業ユーザー向け”">​</a></h3><ul><li>開発ツールを社内で共有</li><li>チームリソースの同期</li><li>オフライン環境へのデプロイ</li></ul><h2 id="_01-5-セキュリティ" tabindex="-1">01.5- セキュリティ <a class="header-anchor" href="#_01-5-セキュリティ" aria-label="Permalink to “01.5- セキュリティ”">​</a></h2><ul><li>✅ 二重暗号化保護</li><li>✅ 自動ファイルクリーンアップ</li><li>✅ ユーザーデータ収集なし</li><li>✅ 安全な転送プロトコル</li></ul><h2 id="_01-6-フィードバック" tabindex="-1">01.6- フィードバック <a class="header-anchor" href="#_01-6-フィードバック" aria-label="Permalink to “01.6- フィードバック”">​</a></h2><p>ご質問やご提案がございましたら、以下の方法でお問い合わせください：</p><ul><li>GitHub Issues</li><li>メールフィードバック</li><li>オンラインカスタマーサービス</li></ul><hr><p><strong>免責事項</strong>: 本ツールは学習および研究目的のみに使用してください。GitHubの利用規約および関連法規を遵守してください。</p>',24)]))}const u=i(n,[["render",s]]);export{b as __pageData,u as default};
